	beforeAll,
	describe,
	expect,
	setDefaultTimeout,
	test,
} from "bun:test";

setDefaultTimeout(30_000);

import { mkdirSync, mkdtempSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import {
	signUpTestUser,
	startTestWorker,
	type TestWorker,
} from "./helpers/wrangler-server.js";

let worker: TestWorker;
let configDir: string;
let tempDir: string;
let sessionToken: string;

beforeAll(async () => {
	tempDir = mkdtempSync(join(tmpdir(), "rudel-auth-test-"));
	configDir = join(tempDir, "config");
	mkdirSync(configDir, { recursive: true });

	worker = await startTestWorker();
	sessionToken = await signUpTestUser(worker.baseUrl);
}, 60_000);

afterAll(async () => {
	await worker?.stop();
	rmSync(tempDir, { recursive: true, force: true });
});

describe("auth e2e", () => {
	test("login: callback server receives token and stores credentials", async () => {
		// Clear any existing credentials first
		clearCredentialsFromDir(configDir);

		const cliPath = join(import.meta.dir, "..", "bin", "cli.ts");
		const stdoutLogPath = join(tempDir, "login-stdout.log");

		// Start login via shell, tee stdout to a file so we can poll it
		const loginProcess = Bun.spawn(
			[
				"bash",
				"-c",
				`bun "${cliPath}" login --api-base="${worker.baseUrl}" --web-url=http://localhost:9999 2>&1 | tee "${stdoutLogPath}"`,
			],
			{
				env: {
					...process.env,
					RUDEL_CONFIG_DIR: configDir,
				},
				stdout: "pipe",
				stderr: "pipe",
			},
		);

