import * as schema from "@rudel/sql-schema";
import { drizzle } from "drizzle-orm/postgres-js";
import postgres from "postgres";

const connectionString = process.env.DATABASE_URL;
if (!connectionString) {
	throw new Error("DATABASE_URL environment variable is required");
}

const client = postgres(connectionString);
export const db = drizzle(client, { schema });

content.content:
  1→import { resolve } from "node:path";
  2→
  3→const MONOREPO_ROOT = resolve(import.meta.dir, "..", "..", "..", "..", "..");
  4→
  5→export interface TestServer {
  6→	port: number;
  7→	baseUrl: string;
  8→	rpcUrl: string;
  9→	stop: () => Promise<void>;
 10→}
 11→
 12→/**
 13→ * Spawn the Bun API server with PORT=0 so the OS picks a free port.
 14→ * Migrations run automatically at startup.
 15→ */
 16→export async function startTestServer(): Promise<TestServer> {
 17→	const proc = Bun.spawn(["bun", "run", "apps/api/src/index.ts"], {
 18→		cwd: MONOREPO_ROOT,
 19→		stdout: "pipe",
 20→		stderr: "pipe",
 21→		env: {
 22→			...process.env,
 23→			PORT: "0",
 24→			APP_URL: "http://localhost",
 25→			BETTER_AUTH_SECRET: "test-secret-for-integration-tests",
 26→			ALLOWED_ORIGIN: "http://localhost",
 27→		},
 28→	});
 29→
 30→	const port = await parseReadyPort(proc);
 31→
 32→	const baseUrl = `http://localhost:${port}`;
 33→	const rpcUrl = `${baseUrl}/rpc`;
 34→
 35→	return {
 36→		port,
 37→		baseUrl,
 38→		rpcUrl,
 39→		async stop() {
 40→			proc.kill();
 41→			await proc.exited;
 42→		},
 43→	};
 44→}
 45→
 46→/**
 47→ * Read stdout line-by-line until the server prints its "listening on" URL,
 48→ * then extract the port from it.
 49→ */
 50→async function parseReadyPort(
 51→	proc: ReturnType<typeof Bun.spawn>,
 52→): Promise<number> {
 53→	const stdout = proc.stdout;
 54→	if (!stdout || !(stdout instanceof ReadableStream)) {
 55→		throw new Error("Server process has no readable stdout");
 56→	}
 57→
 58→	const reader = stdout.getReader();
 59→	const decoder = new TextDecoder();
 60→	let buffer = "";
 61→	const deadline = Date.now() + 30_000;
 62→
 63→	try {
 64→		while (Date.now() < deadline) {
 65→			const { value, done } = await reader.read();
 66→			if (done) break;
 67→			buffer += decoder.decode(value, { stream: true });
 68→
 69→			// index.ts prints: "API server listening on http://localhost:<port>"
 70→			const match = buffer.match(/listening on https?:\/\/localhost:(\d+)/i);
 71→			if (match?.[1]) {
 72→				reader.releaseLock();
 73→				return Number.parseInt(match[1], 10);
 74→			}
 75→		}
 76→	} catch {
 77→		// reader error — fall through to throw
 78→	}
 79→
 80→	// If we get here we failed — grab stderr for diagnostics
 81→	let stderrText = "";
